const data = $input.first().json;
const workflowName = data.workflow?.name || data.workflowName || 'Unknown Workflow';
const errorMsg = data.execution?.error?.message || data.error?.message || JSON.stringify(data.execution?.error || data.error || 'Unknown error');
const executionId = data.execution?.id || data.executionId || 'unknown';
const nodeName = data.execution?.error?.node?.name || data.error?.node?.name || 'unknown node';
const content = `**RIS Unhandled Error**

Workflow: ${workflowName}
Node: ${nodeName}
Execution ID: ${executionId}

Error:
\`\`\`
${String(errorMsg).substring(0, 1500)}
\`\`\``;
return [{ json: { content, workflowName, executionId } }];
